// Case: Ignored error return from a write that can fail.
package writer

import (
	"os"
)

func SaveConfig(path string, contents []byte) {
	// BUG: WriteFile's error is discarded. If the disk is full, permissions
	// are wrong, or the path is invalid, the failure is silently swallowed and
	// callers proceed as if the config was saved.
	os.WriteFile(path, contents, 0o600)
}

// Case: Hardcoded database credentials in a Go service.
package db

const (
	// BUG: production database credentials are committed in plaintext.
	dsnUser = "billing_admin"
	dsnPass = "supersecret-prod-2024"
	dsnHost = "10.0.0.5:5432"
	dsnName = "billing"
)

func DSN() string {
	return "postgres://" + dsnUser + ":" + dsnPass + "@" + dsnHost + "/" + dsnName
}

// Case: Nil-pointer dereference when a lookup returns no value.
package user

type User struct {
	ID    int
	Email string
}

func FindUser(users map[int]*User, id int) string {
	// BUG: FindUser returns the dereferenced Email without checking that the
	// map lookup returned a non-nil pointer. A missing id causes a nil pointer
	// dereference and a process crash.
	u := users[id]
	return u.Email
}

// Case: Data race on a shared map accessed from concurrent goroutines
// without synchronization.
package cache

import (
	"sync"
)

type Cache struct {
	mu   sync.Mutex
	data map[string]string
}

func NewCache() *Cache {
	return &Cache{data: make(map[string]string)}
}

// Get is called from many goroutines but reads the map without holding mu.
func (c *Cache) Get(key string) (string, bool) {
	v, ok := c.data[key] // BUG: unsynchronized concurrent map read
	return v, ok
}

// Set holds the lock, but concurrent reads above still race with writes here.
func (c *Cache) Set(key, value string) {
	c.mu.Lock()
	c.data[key] = value
	c.mu.Unlock()
}

// Case: SQL injection via fmt.Sprintf in a Go database query.
package store

import (
	"database/sql"
	"fmt"
)

func FindByEmail(db *sql.DB, email string) (*sql.Row, error) {
	// BUG: email is interpolated into the query string with fmt.Sprintf instead
	// of using parameterized placeholders, allowing SQL injection.
	q := fmt.Sprintf("SELECT id, email FROM users WHERE email = '%s'", email)
	row := db.QueryRow(q)
	return row, row.Err()
}

// Case: Using java.util.Random for security-sensitive tokens.
import java.util.Random;

public class TokenGenerator {
    private static final Random RNG = new Random();

    // BUG: java.util.Random is a predictable PRNG. Session/reset tokens derived
    // from it can be guessed by an attacker who observes one output, because
    // the internal seed is recoverable. Use SecureRandom instead.
    public static String resetToken() {
        return Long.toHexString(RNG.nextLong());
    }
}

// Case: Arbitrary code execution via eval() on user input.
'use strict';

function buildFilter(expression) {
  // BUG: the caller-supplied expression is passed straight to eval(), so any
  // user-controlled value becomes running JavaScript (e.g. stealing cookies
  // via fetch, or crashing the process).
  const predicate = eval('(' + expression + ')');
  return (item) => predicate(item);
}

module.exports = { buildFilter };

// Case: Open redirect via unvalidated user-controlled URL.
const express = require('express');
const app = express();

app.get('/login', (req, res) => {
  // BUG: the `next` query param is used directly in res.redirect without any
  // allowlist or same-origin check, so an attacker can craft
  // /login?next=https://evil.example to phish users off the trusted domain.
  const next = req.query.next;
  if (next) {
    return res.redirect(next);
  }
  res.redirect('/dashboard');
});

# Case: Bare except swallows all errors including KeyboardInterrupt.
import json


def parse_config(raw: str) -> dict:
    try:
        return json.loads(raw)
    except:  # BUG: catches BaseException, hiding bugs, KeyboardInterrupt, and
            # SystemExit, and returns an empty dict so callers never learn the
            # config failed to parse.
        return {}


def load_settings(path: str) -> dict:
    with open(path, "r", encoding="utf-8") as fh:
        return parse_config(fh.read())

# Case: Using MD5 to hash passwords.
import hashlib


def hash_password(password: str) -> str:
    # BUG: MD5 is cryptographically broken and unsalted, so identical passwords
    # produce identical hashes that are trivially cracked via rainbow tables.
    return hashlib.md5(password.encode()).hexdigest()


def verify_password(password: str, stored: str) -> bool:
    return hash_password(password) == stored

// Case: Unchecked arithmetic that panics on overflow and can wrap balances.
pub struct Account {
    pub balance: u64,
}

impl Account {
    pub fn credit(&mut self, amount: u64) {
        // BUG: in debug builds this panics on overflow; in release builds it
        // wraps silently, so crediting a huge amount can roll the balance back
        // to a small value. Use checked_add / saturating_add explicitly.
        self.balance += amount;
    }

    pub fn debit(&mut self, amount: u64) -> u64 {
        // BUG: subtraction underflow panics in debug and wraps in release,
        // letting an over-debit produce a huge balance.
        self.balance -= amount;
        self.balance
    }
}

// Case: Dead/unreachable code after an unconditional return.
export function classify(score: number): string {
  if (score >= 90) {
    return 'A';
  }
  if (score >= 80) {
    return 'B';
  }
  return 'C';

  // BUG: everything below this point is unreachable. The unconditional return
  // above means this branch can never execute, and the helper is never used.
  if (score >= 70) {
    return 'D';
  }
  return 'F';
}

function neverCalled(): void {
  console.log('this function has no callers');
}

// Case: Hardcoded database credentials in a TypeScript service config.
export const dbConfig = {
  host: 'db.prod.internal',
  port: 5432,
  user: 'admin',
  // BUG: the production database password is committed in plaintext.
  password: 'P@ssw0rd-prod-2024!',
  database: 'orders',
};

export async function connect() {
  const url = `postgres://${dbConfig.user}:${dbConfig.password}@${dbConfig.host}:${dbConfig.port}/${dbConfig.database}`;
  return fetch(url);
}

// Case: Session cookie set without Secure, HttpOnly, or SameSite attributes.
import type { Response } from 'express';

export function setSessionCookie(res: Response, token: string): void {
  // BUG: the cookie is set without Secure (sent over HTTP), HttpOnly (readable
  // by JS/XSS), and SameSite (vulnerable to CSRF). A stolen cookie value is a
  // stolen session.
  res.cookie('session', token, { maxAge: 86400000 });
}

// Case: Missing await on a rejected promise swallows an error.
import { deleteSession } from './session';

export async function logout(userId: string): Promise<void> {
  // BUG: deleteSession returns a promise but is not awaited. If it rejects,
  // the rejection becomes an unhandled promise rejection and logout resolves
  // as if the session were deleted, leaving stale sessions behind.
  deleteSession(userId);
  console.log('user logged out');
}

// Case: Prototype pollution via recursive object merge.
function isObject(v: unknown): v is Record<string, unknown> {
  return typeof v === 'object' && v !== null;
}

// BUG: the merge walks user-supplied keys without blocking __proto__,
// constructor, or prototype. A payload like {"__proto__": {"admin": true}}
// pollutes Object.prototype and escalates privileges app-wide.
export function merge(target: Record<string, unknown>, source: unknown): Record<string, unknown> {
  if (!isObject(source)) return target;
  for (const key of Object.keys(source)) {
    const tv = target[key];
    const sv = source[key];
    if (isObject(tv) && isObject(sv)) {
      merge(tv, sv);
    } else {
      target[key] = sv;
    }
  }
  return target;
}

// Case: Catastrophic backtracking regex (ReDoS).
// This regex is used to validate user-supplied email-like strings.
export const emailLikePattern = /^([a-zA-Z0-9._%+-]+)+$/;

// BUG: the nested + quantifier ((...+)+) creates exponential backtracking on
// non-matching inputs. A long string like "a".repeat(30) + "!" hangs the event
// loop and denies service to all other requests.
export function isEmailLike(input: string): boolean {
  return emailLikePattern.test(input);
}

// Case: SQL injection via string concatenation in a TypeScript query builder.
import { db } from './db';

interface User {
  id: number;
  email: string;
}

export async function findUserByEmail(emailInput: string): Promise<User | null> {
  // BUG: user-controlled emailInput is concatenated directly into the SQL
  // string, allowing an attacker to break out of the quoted value and append
  // arbitrary SQL (e.g. "' OR '1'='1").
  const sql = `SELECT id, email FROM users WHERE email = '${emailInput}' LIMIT 1`;
  const rows = await db.query<User>(sql);
  return rows[0] ?? null;
}

// Case: Type-safety bypass via `as any` that hides a real shape mismatch.
interface Order {
  id: string;
  total: number;
  items: string[];
}

interface Refund {
  id: string;
  amount: number;
  reason: string;
}

// BUG: the caller casts the payload to `any` so the compiler cannot catch that
// a Refund is being treated as an Order. At runtime `items` is undefined and
// the .length access throws, or worse, silently corrupts downstream totals.
export function processOrder(payload: unknown): number {
  const order = payload as any as Order;
  return order.total + order.items.length;
}

// Case: Reflected XSS via dangerouslySetInnerHTML in a React component.
import React from 'react';

interface CommentProps {
  body: string; // user-supplied comment markdown/html
}

export const Comment: React.FC<CommentProps> = ({ body }) => {
  // BUG: raw user-supplied content is rendered as HTML without sanitization.
  // An attacker can inject <script> or event-handler payloads that execute in
  // every viewer's session.
  return <div dangerouslySetInnerHTML={{ __html: body }} />;
};
